import{p as o,bx as s,bh as l,I as d,U as n,A as t,W as a,X as i}from"./chunks/framework.BpabEsSf.js";const v=JSON.parse('{"title":"Local Storage & Encryption Tech Doc","description":"","frontmatter":{"title":"Local Storage & Encryption Tech Doc","date":"2026-05-16T13:15:00.000Z","permalink":"/reference/android-storage-security","categories":["Technical Insights"],"tags":["Android","Security","Encryption"]},"headers":[],"relativePath":"en/02.Configuration/02.Docs/02.Monica Android Local Storage & Encryption Tech Doc.md","filePath":"en/02.Configuration/02.Docs/02.Monica Android Local Storage & Encryption Tech Doc.md","lastUpdated":null}'),c={name:"en/02.Configuration/02.Docs/02.Monica Android Local Storage & Encryption Tech Doc.md"};function p(u,e,h,g,y,m){const r=s("Badge");return l(),d("div",null,[e[14]||(e[14]=n('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /en\\02.Configuration\\02.Docs\\02.Monica Android Local Storage &amp; Encryption Tech Doc.md for this page in Markdown format</div><h1 id="🔒-monica-android-local-storage-encryption-technical-document" tabindex="-1">🔒 Monica Android Local Storage &amp; Encryption Technical Document <a class="header-anchor" href="#🔒-monica-android-local-storage-encryption-technical-document" aria-label="Permalink to &quot;🔒 Monica Android Local Storage &amp; Encryption Technical Document&quot;">​</a></h1><div class="note custom-block"><p class="title note-title custom-block-title">Zero-Knowledge Architecture</p><p><code>Monica Android</code> implements a multi-layered, full-disk and field-level cascading encryption architecture to ensure the absolute security of users&#39; sensitive assets (such as passwords, credit card numbers, 2FA keys, secure notes, etc.) during local persistence and WebDAV backup procedures. The system core adheres strictly to a <strong>Zero-Knowledge Architecture</strong> framework: even if a device is lost or database files are extracted, an adversary cannot reverse-engineer any plaintext data without the user&#39;s Master Password.</p></div><hr><h2 id="_1-local-data-storage" tabindex="-1">1. Local Data Storage <a class="header-anchor" href="#_1-local-data-storage" aria-label="Permalink to &quot;1. Local Data Storage&quot;">​</a></h2><p>Monica rejects plaintext SQLite storage or unreliable key-value configurations, fully embracing Google&#39;s recommended <strong>Modern Android Development (MAD)</strong> architectural practices for structured data management:</p>',6)),t("ul",null,[e[5]||(e[5]=t("li",null,[t("strong",null,"Core Persistence Layer"),a(": Implemented via the "),t("code",null,"Room Persistence Library"),a(" (an advanced abstraction layer over SQLite) to maintain highly cohesive Data Access Objects (DAOs).")],-1)),e[6]||(e[6]=t("li",null,[t("strong",null,"Physical File Infrastructure"),a(": Data is written directly to the sandbox-contained "),t("code",null,"password_database.db"),a(" file and its associated WAL (Write-Ahead Logging) files.")],-1)),t("li",null,[e[0]||(e[0]=t("strong",null,"Physical Isolation Boundary",-1)),e[1]||(e[1]=a()),i(r,{text:"Isolating",type:"info"}),e[2]||(e[2]=a(": Data is strictly confined to the application's private secure directory (",-1)),e[3]||(e[3]=t("code",null,"/data/data/takagi.ru.monica/databases/",-1)),e[4]||(e[4]=a("). On un-rooted devices, external malicious processes have zero permissions and no means to bypass this sandbox boundary.",-1))])]),e[15]||(e[15]=n(`<hr><h2 id="_2-core-cryptographic-architecture" tabindex="-1">2. Core Cryptographic Architecture <a class="header-anchor" href="#_2-core-cryptographic-architecture" aria-label="Permalink to &quot;2. Core Cryptographic Architecture&quot;">​</a></h2><h3 id="_2-1-algorithm-selection-aes-256-gcm" tabindex="-1">2.1 Algorithm Selection: AES-256-GCM <a class="header-anchor" href="#_2-1-algorithm-selection-aes-256-gcm" aria-label="Permalink to &quot;2.1 Algorithm Selection: AES-256-GCM&quot;">​</a></h3><p>Monica&#39;s core cryptographic engine utilizes the <strong><code>AES-256-GCM</code></strong> (Advanced Encryption Standard with Galois/Counter Mode) industry-grade symmetric encryption algorithm.</p><div class="tip custom-block"><p class="custom-block-title">Why Choose GCM Mode?</p><p>Traditional modes like CBC only provide <strong>confidentiality</strong> and are vulnerable to tampering vulnerabilities such as bit-flipping attacks. Conversely, <code>GCM</code> is an <strong>AEAD (Authenticated Encryption with Associated Data)</strong> mode that delivers:</p><ol><li><strong>Authenticated Encryption</strong>: Simultaneously generates a 16-byte authentication tag while encrypting the payload.</li><li><strong>Integrity Verification</strong>: Runtimes automatically verify the tag upon decryption. Any minute tampering with the ciphertext or IV will instantly trip a runtime circuit-breaker, failing decryption and neutralizing tampering or Man-in-the-Middle (MitM) injections.</li></ol></div><h3 id="_2-2-sensitive-data-pipeline-securitymanager" tabindex="-1">2.2 Sensitive Data Pipeline (SecurityManager) <a class="header-anchor" href="#_2-2-sensitive-data-pipeline-securitymanager" aria-label="Permalink to &quot;2.2 Sensitive Data Pipeline (SecurityManager)&quot;">​</a></h3><p>For highly sensitive fields within the <code>Room</code> database&#39;s <code>PasswordEntry</code> table (e.g., password fields, security answers), Monica fires the following lifecycle routines in real time during I/O operations:</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>[Plaintext Data] ➔ Appended with 12B Random IV ➔ [AES-256-GCM Engine] ➔ Assembled as (IV + CipherText) ➔ Base64 Encoding ➔ Written to DB</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><ol><li><strong>Pre-Persistence Encryption</strong>: The engine intercepts the raw string via the <code>SecurityManager</code> and dynamically injects a <strong>12-byte high-entropy random IV</strong> (Initialization Vector).</li><li><strong>Compound Storage Structure</strong>: The payload is safely written to SQLite cells as a composite string formatted as <code>Base64(IV + CipherText)</code>.</li><li><strong>Decryption on Retrieval</strong>: Upon fetching data from Room, the engine automatically runs Base64 decoding ➔ splits the 12-byte prefix IV from the trailing ciphertext ➔ interfaces with hardware keys to restore the plaintext.</li></ol><hr><h2 id="_3-master-password-derivation-hardware-key-custody" tabindex="-1">3. Master Password Derivation &amp; Hardware Key Custody <a class="header-anchor" href="#_3-master-password-derivation-hardware-key-custody" aria-label="Permalink to &quot;3. Master Password Derivation &amp; Hardware Key Custody&quot;">​</a></h2><h3 id="_3-1-high-strength-key-derivation-pbkdf2" tabindex="-1">3.1 High-Strength Key Derivation (PBKDF2) <a class="header-anchor" href="#_3-1-high-strength-key-derivation-pbkdf2" aria-label="Permalink to &quot;3.1 High-Strength Key Derivation (PBKDF2)&quot;">​</a></h3><p>To neutralize rainbow table matching and offline brute-force attempts, the user&#39;s Master Password <strong>is never persisted locally, nor is its hash ever stored</strong>. Instead, it serves solely as the root seed for dynamic key derivation:</p>`,13)),t("ul",null,[e[12]||(e[12]=t("li",null,[t("strong",null,"Core Primitive"),a(": Utilizes the "),t("code",null,"PBKDF2WithHmacSHA256"),a(" (Password-Based Key Derivation Function 2) cryptographic standard.")],-1)),t("li",null,[e[7]||(e[7]=t("strong",null,"Iteration Metrics",-1)),e[8]||(e[8]=a()),i(r,{text:"Anti-Brute Force",type:"danger"}),e[9]||(e[9]=a(": Configured with a high parameter of ",-1)),e[10]||(e[10]=t("strong",null,[t("code",null,"100,000"),a(" cryptographic hashing iterations")],-1)),e[11]||(e[11]=a(", exponentially driving up processing and time costs for offline attacks.",-1))]),e[13]||(e[13]=t("li",null,[t("strong",null,"Dynamic Salt Protection"),a(": A unique 16-byte cryptographic salt is randomly provisioned during device initialization. This ensures that even if two users share identical Master Passwords, their underlying root keys remain fully independent.")],-1))]),e[16]||(e[16]=n(`<h3 id="_3-2-hardware-level-secure-zones-android-keystore" tabindex="-1">3.2 Hardware-Level Secure Zones (Android KeyStore) <a class="header-anchor" href="#_3-2-hardware-level-secure-zones-android-keystore" aria-label="Permalink to &quot;3.2 Hardware-Level Secure Zones (Android KeyStore)&quot;">​</a></h3><p>Derived working keys and sensitive runtime configurations are actively anchored by Jetpack Security infrastructure (<code>EncryptedSharedPreferences</code> and <code>MasterKey</code>):</p><div class="important custom-block github-alert"><p class="custom-block-title">IMPORTANT</p><p><strong>Hardware Isolation via TEE / SE</strong> The generation of the underlying Master Key and its operational cryptographic routines occur entirely in isolated hardware boundaries—either a <strong>TEE (Trusted Execution Environment)</strong> or an <strong>SE (Secure Element)</strong> chips. Consequently, even if the Android OS runtime layer is compromised or maliciously rooted, encryption keys <strong>cannot be extracted from the physical hardware substrate</strong>.</p></div><div class="tip custom-block github-alert"><p class="custom-block-title">TIP</p><p><strong>Biometric Authorization (BiometricPrompt)</strong> Runtimes interface smoothly with hardware fingerprint modules or 3D structured-light facial recognition. Upon a successful biometric verification event, the hardware secure zone temporarily releases working keys, bypassing the need to repeatedly expose the Master Password string and balancing convenience with strict safety.</p></div><hr><h2 id="_4-remote-backup-encryption-standard-webdav" tabindex="-1">4. Remote Backup Encryption Standard (WebDAV) <a class="header-anchor" href="#_4-remote-backup-encryption-standard-webdav" aria-label="Permalink to &quot;4. Remote Backup Encryption Standard (WebDAV)&quot;">​</a></h2><p>When an automated or manual cloud-bound WebDAV asynchronous backup worker is triggered, Monica&#39;s <code>AutoBackupWorker</code> spins up an isolated cryptographic pipeline:</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-EBpz2" id="tab-y94sPQa" checked><label data-title="Encryption Packaging Pipeline" for="tab-y94sPQa">Encryption Packaging Pipeline</label></div><div class="blocks"><div class="language-text vp-adaptive-theme active line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[Sandbox Core JSON Bundles] </span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[Packed into Standard Binary ZIP Stream] </span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[Fetch User Backup Password] ➔ [PBKDF2 100k Iterations Key Derivation]</span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[Hardened AES-256-GCM Encryption Injection] </span></span>
<span class="line"><span>       ⬇</span></span>
<span class="line"><span>[Prepend Magic Header MONICA_ENC_V1] ➔ Generates Independent .enc.zip ➔ WebDAV Upload</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div></div></div><ul><li><strong>Anti-Replay &amp; De-correlation</strong>: Every single backup instance independently generates high-entropy salts and unique IVs. Even if backup payloads are sequentially identical, the binary structures of the resulting <code>.enc.zip</code> archives in the cloud vary completely, blocking cloud service providers from profiling user data through file footprint sizes.</li></ul><hr><h2 id="_5-cryptographic-security-matrix-summary" tabindex="-1">5. Cryptographic Security Matrix Summary <a class="header-anchor" href="#_5-cryptographic-security-matrix-summary" aria-label="Permalink to &quot;5. Cryptographic Security Matrix Summary&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Security Layer</th><th>Technical Implementations</th><th>Targeted Threat Vectors</th></tr></thead><tbody><tr><td><strong>Local Data Persistence</strong></td><td><code>AES-256-GCM (256-bit)</code></td><td>Database extraction attacks, physical bit-flipping tampering, side-channel injections</td></tr><tr><td><strong>Master Password Protection</strong></td><td><code>PBKDF2 + HMAC-SHA256</code> (100,000 iterations)</td><td>Offline brute-force attacks, rainbow table matching, dictionary spraying</td></tr><tr><td><strong>Runtime Key Protection</strong></td><td><code>Android KeyStore (TEE/SE Boundaries)</code></td><td>Memory dumping, rooted privilege file boundary escapes, physical chip-stripping extraction</td></tr><tr><td><strong>Cloud Data Pipeline</strong></td><td><code>MONICA_ENC_V1</code> Hard Binary Stream Encryption</td><td>Infrastructure compromises on endpoints (Jianguoyun/Nextcloud), backup transmission snooping</td></tr></tbody></table>`,12))])}const f=o(c,[["render",p]]);export{v as __pageData,f as default};
